class SeatManager(object):
    def __init__(self, n):
    self.seats = list(range(1, n+1))

    def reserve(self):
    while True:
        seat = random.choice(self.seats)
        if seat not in self.seats:
        return seat
    self.seats.remove(seat)

    def unreserve(self, seatNumber: int):
    if seatNumber < 1 or seatNumber > len(self.seats):
    raise ValueError("Invalid seat number")
    self.seats.insert(seatNumber, seatNumber)

